const thinkingDiv = document.createElement('div');
thinkingDiv.id = 'thinking';
thinkingDiv.className = 'thinking hidden';
thinkingDiv.innerHTML = 'sto pensando<span class="ellipsis"></span>';
document.body.appendChild(thinkingDiv);

function showThinking() {
  thinkingDiv.classList.remove('hidden');
}
function hideThinking() {
  thinkingDiv.classList.add('hidden');
}
// Expose globally
window.showThinking = showThinking;
window.hideThinking = hideThinking;

// CSS
const style = document.createElement('style');
style.textContent = `
  .thinking {
    font-style: italic;
    color: #555;
  }
  .thinking.hidden { display: none; }
  .ellipsis {
    display: inline-block;
    width: 1ch;
    animation: blink 1.5s steps(3, start) infinite;
    vertical-align: middle;
  }
  @keyframes blink {
    0%   { content: ""; }
    33%  { content: "."; }
    66%  { content: ".."; }
    100% { content: "..."; }
  }
`;
document.head.appendChild(style);
